-- Ensure it's a positive integer
if numeric_id ~= math.floor(numeric_id) or numeric_id <= 0 then
    ngx.status = 400
    ngx.header.content_type = "application/json"
    ngx.say('{"error": "Parameter id must be a positive integer"}')
    return ngx.exit(400)
end

-- Create PostgreSQL connection
local pg = pgmoon.new({
    host = os.getenv("PG_HOST") or "127.0.0.1",
    port = tonumber(os.getenv("PG_PORT")) or 5432,
    database = os.getenv("PG_DATABASE") or "myapp",
    user = os.getenv("PG_USER") or "postgres",
    password = os.getenv("PG_PASSWORD") or "postgres",
    socket_type = "nginx",  -- Use cosocket for OpenResty
})

-- Connect to the database
local ok, err = pg:connect()
if not ok then
    ngx.status = 500
    ngx.header.content_type = "application/json"
    ngx.say('{"error": "Failed to connect to database: ' .. (err or "unknown error") .. '"}')
    return ngx.exit(500)
